import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine(); // Read the entire line

        // Limiting buffer size to avoid buffer overflow
        int bufferSize = Math.min(userInput.length(), 10);
        char[] buffer = new char[bufferSize];

        userInput.getChars(0, bufferSize, buffer, 0);

        // Printing only up to the actual input length
        for (int i = 0; i < bufferSize; i++) {
            System.out.print(buffer[i]);
        }

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
